issues.recommendation:
Add a matching focus-visible style so keyboard users receive the same cues.
Example:
#main p a:focus-visible {
  color: #39275b;
  text-decoration: underline;
}

issues.lineContent:
a:hover, a:focus, input:focus {
  outline: none;
  border-color: transparent;
}

issues.recommendation:
Do not remove focus outlines. If customizing, provide a strong, visible focus style using :focus-visible with sufficient contrast.
Example:
a:focus-visible, input:focus-visible {
  outline: 3px solid #005fcc;
  outline-offset: 2px;
}
/* Avoid setting border-color: transparent on focused elements unless a clear alternative indicator is provided. */

Add an Escape key handler while the modal is open and remove it on close. Example:

$(document).on('keydown.modal', function(e){
  if (e.key === 'Escape') {
    hideModal();
    if (window._modalTrigger) { window._modalTrigger.focus(); }
    $(document).off('keydown.modal');
  }
});

On open, move focus into the modal and optionally trap focus within it. Store the trigger to restore focus on close. Example:

window._modalTrigger = document.activeElement;
const $modal = $('#modalContent');
$modal.attr('tabindex','-1').focus();
$(document).on('keydown.modal', function(e){
  if (e.key === 'Tab') {
    const $focusables = $modal.find('button,[href],input,select,textarea,[tabindex]:not([tabindex="-1"])');
    const first = $focusables.first()[0];
    const last = $focusables.last()[0];
    if (e.shiftKey && document.activeElement === first) { e.preventDefault(); $(last).focus(); }
    else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); $(first).focus(); }
  }
});

Save the triggering element before opening the modal and focus it when the modal closes. Example:

$('a[href="cheatsheet.html"]').on('click', function(event) {
  window._modalTrigger = event.currentTarget;
  showModal();
  event.preventDefault();
});

// In hideModal():
function hideModal(){
  // ...existing hide code...
  if (window._modalTrigger) { window._modalTrigger.focus(); }
  $(document).off('keydown.modal');
}

When showing the modal, programmatically move focus to the modal container or its first focusable element, and store the previously focused element to restore on close.
Example:
function showModal() {
  // ...positioning...
  const previouslyFocused = document.activeElement;
  const $modal = $('#modalContent');
  $modal.attr('tabindex', '-1').show().focus();
  $modal.data('returnFocus', previouslyFocused);
}
function hideModal() {
  const $modal = $('#modalContent');
  $modal.hide();
  const returnFocus = $modal.data('returnFocus');
  if (returnFocus) $(returnFocus).focus();
}

When showing the modal, move focus into it and make the container focusable. Example:

var prevFocus = document.activeElement;
$('#modalContent').attr({ role: 'dialog', 'aria-modal': 'true', tabindex: '-1' }).focus();
// Store prevFocus in a closure or higher scope to restore on hide

Add an Escape key handler while the modal is open. Example:

function showModal() {
  // existing show code...
  function onKeydown(e) { if (e.key === 'Escape') hideModal(); }
  $(document).on('keydown.modal', onKeydown);
}
function hideModal() {
  // existing hide code...
  $(document).off('keydown.modal');
}

Implement focus trapping when the modal is open by cycling Tab between the first and last focusable elements inside the modal. Example:

const $modal = $('#modalContent');
const focusable = $modal.find('a, button, input, select, textarea, [tabindex]:not([tabindex="-1"])');
const first = focusable.first()[0];
const last = focusable.last()[0];
$modal.on('keydown.modalTrap', function(e){
  if (e.key === 'Tab') {
    if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
    else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
  }
});
// remove handler on hide: $modal.off('keydown.modalTrap');

Store the previously focused element before opening the modal and restore focus on hide. Example:

let prevFocus;
function showModal() {
  prevFocus = document.activeElement;
  // show code + focus modal
}
function hideModal() {
  $('#modalContent').hide();
  $('#modalMask').hide();
  if (prevFocus) prevFocus.focus();
}

Add a keydown listener for Escape while the modal is open to call hideModal(). For example:
$(document).on('keydown.modal', function(e){
  if (e.key === 'Escape') {
    hideModal();
  }
});

On open, move focus to the modal container (make it focusable) and trap focus within it. For example inside showModal():
var lastFocus = document.activeElement;
$('#modalContent').attr('tabindex','-1').show().focus();

Store the triggering element before opening the modal and restore focus on close. For example:
// before opening
var lastFocus = document.activeElement;
// on close
hideModal();
if (lastFocus) { $(lastFocus).focus(); }
$(document).off('keydown.modal');

issues.lineContent:
#btn-prev {
  border-top: 40px solid transparent;
  border-bottom: 40px solid transparent;   
  border-right: 40px solid #E9E9ED;   
  left: 5px;
}

issues.recommendation:
Provide a visible focus indicator for keyboard users. Example:

#btn-prev:focus-visible {
  outline: 3px solid #000;
  outline-offset: 2px;
}

Also ensure the control uses a semantic <button id="btn-prev"> or, if custom, make it focusable and operable via keyboard (e.g., tabindex="0" and Enter/Space handlers).

issues.lineContent:
#btn-next {
  border-top: 40px solid transparent;
  border-bottom: 40px solid transparent;  
  border-left: 40px solid #E9E9ED;
  right: 5px;
}

issues.recommendation:
Provide a visible focus indicator for keyboard users. Example:

#btn-next:focus-visible {
  outline: 3px solid #000;
  outline-offset: 2px;
}

Also ensure the control uses a semantic <button id="btn-next"> or, if custom, make it focusable and operable via keyboard (e.g., tabindex="0" and Enter/Space handlers).

issues.lineContent:
.lentils li {
  display: inline-block;
  width: 20px;
  height: 20px;
  margin: 10px;
  text-indent: 0;
  cursor: pointer;
  border: none;
  border-radius: 50%;
  background-color: #FFF;
  box-shadow: inset 1px 1px 1px 1px rgba(0,0,0,0.5);
}
.lentils li.active {
  width: 20px;
  height: 20px;
  margin: 10px;
  background-color: #FF9; /* yellow */
}

issues.recommendation:
Add focus-visible styles and ensure focusability if using custom elements. Example:

.lentils li:focus-visible {
  outline: 3px solid #000;
  outline-offset: 2px;
}
.lentils li.active:focus-visible {
  outline: 3px solid #000;
  outline-offset: 2px;
}

Prefer semantic markup, e.g., <button class="lentil"> inside the LI, or make the LI focusable (tabindex="0") and ensure keyboard activation (Enter/Space). Pair any :hover styles with :focus-visible if added.

Remove the outline reset or replace it with a visible focus style. Example:
/* Remove the outline reset */
/* #modalContent button { outline: none; } */
#modalContent button:focus-visible { outline: 3px solid #005fcc; outline-offset: 2px; }

Add a matching :focus-visible style so keyboard focus receives the same visual treatment as hover.

Example:
#menu a:hover,
#menu a:focus-visible {
  background: #39275b;
  color: #FFF;
}

Provide a clearly visible focus indicator with adequate contrast (≥3:1), such as a high-contrast outline or matching the hover background, and target :focus-visible.

Example:
#menu a:focus-visible {
  outline: 2px solid #000; /* or */
  background: #39275b;
  color: #FFF;
}

Remove the outline reset and provide a visible custom focus style. For example:

#modalContent button { outline: revert; }
#modalContent button:focus-visible {
  outline: 3px solid #005fcc;
  outline-offset: 2px;
}

Alternatively, omit the rule entirely to preserve the browser’s default focus indicator.

issues.lineContent:
#btn-prev,
#btn-next {
  position: absolute;
  width: 0; 
  height: 0;
  z-index: 20;
  top: 30%;  
}

issues.recommendation:
Provide an explicit keyboard focus indicator for these controls. For example:

#btn-prev:focus-visible::after,
#btn-next:focus-visible::after {
  content: "";
  position: absolute;
  left: -12px;
  top: -12px;
  width: 56px;
  height: 56px;
  border: 3px solid #FFD700; /* high-contrast focus ring */
  border-radius: 6px;
}

(Alternatively, use a native <button> with an SVG arrow and add :focus-visible styles.)

Make the indicators keyboard-operable by using semantic buttons or by adding tabindex and key handlers. Example:
var lentil = $('<li>')
  .attr('data-slide', i)
  .attr('role','button')
  .attr('tabindex','0')
  .attr('aria-label', 'Go to slide ' + (i + 1))
  .on('click keydown', function(e){
    if (e.type === 'click' || e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      showSlide($(this).data('slide'));
    }
  });
// Or better, place a <button> inside the <li> and attach the click to the button.

Provide a proper role and accessible name, or use a semantic <button>. Example (keeping <li>):
var lentil = $('<li>')
  .attr('role','button')
  .attr('tabindex','0')
  .attr('aria-label', 'Go to slide ' + (i + 1));
// Update aria-current or aria-selected on the active indicator as appropriate.

Use semantic buttons for the indicators so they are focusable and respond to Enter/Space, or add tabindex and a key handler. Example using buttons:
var lentil = $('<button type="button" class="lentil">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i + 1))
  .on('click keydown', function(e) {
    if (e.type === 'click' || e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      showSlide($(this).data('slide'));
    }
  });

Provide proper semantics and an accessible name. Prefer <button> with an aria-label, or add role, tabindex, and aria-label to the <li>. Example:
var lentil = $('<button type="button" class="lentil">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i + 1));

Use semantic buttons (preferred) or make the <li> focusable and add a keyboard handler. Example (preferred):

var lentil = $('<button type="button" class="lentil">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i + 1))
  .on('click keydown', function(e){
    if (e.type === 'click' || e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      showSlide(parseInt($(this).attr('data-slide'), 10));
    }
  });

If keeping <li>: add role, tabindex, and key handler:

var lentil = $('<li role="button" tabindex="0">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i + 1))
  .on('keydown', function(e){ if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); showSlide($(this).data('slide')); }});

Use a semantic <button> with an accessible name, or add ARIA role, focusability, and a label. Example:

// Use a button
var lentil = $('<button type="button" class="lentil">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i + 1));

// Or keep <li> but add role/name
var lentil = $('<li role="button" tabindex="0">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i + 1));

Additionally, update state for the active indicator when slides change (e.g., set aria-current="true" on the active button and "false" on others).

Use a semantic button for each indicator or make the <li> focusable and handle keyboard activation. For example:

// Option A: Use button (recommended)
var lentil = $('<button type="button" class="lentil-dot">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i+1))
  .on('click', function(){
    showSlide($(this).data('slide'));
  });

// Option B: Keep <li> but add keyboard support
var lentil = $('<li tabindex="0" role="button">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i+1))
  .on('click keydown', function(e){
    if (e.type === 'click' || e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      showSlide($(this).data('slide'));
    }
  });

Provide a proper role and accessible name, or use a native button. For example:

// Using button (preferred)
var lentil = $('<button type="button" class="lentil-dot">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i+1))
  .on('click', function(){ showSlide($(this).data('slide')); });

// Or add role/name to <li>
var lentil = $('<li tabindex="0" role="button">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i+1))
  .on('click keydown', function(e){ if(e.type==='click'||e.key==='Enter'||e.key===' '){ e.preventDefault(); showSlide($(this).data('slide')); }});

Add a keyboard handler to close the submenu when pressing Escape. Example:

document.addEventListener('keydown', function(e){
  if (e.key === 'Escape') {
    closeSubMenu();
  }
});

Add a keyboard equivalent by handling focus leaving the menu (focusout) to trigger the same delayed close, or close immediately. Example:

$('#menu').on('focusout', function(e){
  if (!this.contains(e.relatedTarget)) {
    clearTimeout(timer);
    timer = setTimeout(function(){ closeSubMenu(); }, timeout);
  }
});

Mirror the mouseout behavior for keyboard users by handling focusout and Escape. Example:
$("#menu").on('focusout', function(e){ if (!this.contains(e.relatedTarget)) { timer = setTimeout(closeSubMenu, timeout); } });
$(document).on('keydown', function(e){ if (e.key === 'Escape') { clearTimeout(timer); closeSubMenu(); } });

Use semantic buttons for the indicators or make the <li> focusable and add keyboard handlers. Example replacing with buttons:

$('<li>').append(
  $('<button type="button" class="lentil">')
    .attr('data-slide', i)
    .attr('aria-label', 'Go to slide ' + (i+1))
    .on('click keydown', function(e){
      if (e.type === 'click' || e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        showSlide($(this).data('slide'));
      }
    })
).appendTo(lentils);

If keeping <li> clickable, add tabindex and key handlers:

var lentil = $('<li>')
  .attr('tabindex','0')
  .attr('role','button')
  .attr('aria-label','Go to slide ' + (i+1))
  .on('keydown', function(e){ if (e.key==='Enter'||e.key===' '){ e.preventDefault(); showSlide($(this).data('slide')); } })
  .on('click', function(){ showSlide($(this).data('slide')); });

Provide proper role and accessible name, and update state. Prefer using a <button> with an aria-label. Example:

var button = $('<button type="button" class="lentil">')
  .attr('data-slide', i)
  .attr('aria-label', 'Go to slide ' + (i+1));
$('<li>').append(button).appendTo(lentils);

When a slide becomes current in showSlide(), set aria-current on the active indicator and remove it from others:

$('.lentils button').attr('aria-current', 'false');
$('.lentils button[data-slide="'+index+'"]').attr('aria-current', 'true');

If keeping <li> interactive, add role="button" and aria-label on it.

After showing the new slide, programmatically move focus to it (or a meaningful focusable element within it). Ensure slides can receive programmatic focus.

Example:
// after updating classes
var $slides = $('.slide');
var $newSlide = $slides.eq(index);
$newSlide.attr('tabindex','-1'); // allow programmatic focus
$newSlide.focus(); // only when triggered by keyboard interaction

Update ARIA state when changing slides so hidden slides are marked aria-hidden and the visible slide is not.

Example:
$('.slide').attr('aria-hidden','true');
var $newSlide = $('.slide').eq(index);
$newSlide.attr('aria-hidden','false').addClass('current');

Expose selection state on indicators using appropriate ARIA. If the indicators act like tabs, use role="tab" and aria-selected; otherwise use aria-current on the active control.

Example (tabs pattern):
$('.lentils li').attr({'role':'tab','aria-selected':'false'}).removeClass('active');
$('.lentils li').eq(index).attr('aria-selected','true').addClass('active');

Or (current page/link pattern):
$('.lentils li').removeAttr('aria-current').removeClass('active');
$('.lentils li').eq(index).attr('aria-current','true').addClass('active');

Provide specific, per-field error messages and associate them with the corresponding inputs. Example:

// Example validation
var errors = [];
if (!$('#email').val()) {
  $('#email').attr('aria-invalid', 'true');
  var msgId = 'email-error';
  var msg = $('<span id="' + msgId + '" class="error">Email is required.</span>');
  $('#email').attr('aria-describedby', msgId);
  errors.push({ field: $('#email'), message: 'Email is required.' });
}

// Build an error summary that lists each field-specific error
var summary = $('<div>').addClass('errorSummary');
summary.append('<h2>There were errors with your submission</h2>');
var list = $('<ul>');
errors.forEach(function(e) {
  var id = e.field.attr('id');
  list.append($('<li>').append($('<a>').attr('href', '#' + id).text(e.message)));
});
$('#error').empty().append(summary.append(list)).show();

Only prevent submission when validation fails, and mark invalid inputs with aria-invalid and associate messages via aria-describedby. Example:

var form = document.querySelector('form');
$('#submit').on('click', function(event) {
  var invalids = form.querySelectorAll(':invalid');
  if (invalids.length) {
    event.preventDefault();
    invalids.forEach(function(el) {
      el.setAttribute('aria-invalid', 'true');
      var msgId = el.id + '-error';
      var msgText = el.validationMessage || 'Please correct this field.';
      if (!document.getElementById(msgId)) {
        var msg = document.createElement('span');
        msg.id = msgId;
        msg.className = 'error';
        msg.textContent = msgText;
        el.insertAdjacentElement('afterend', msg);
      }
      el.setAttribute('aria-describedby', msgId);
    });
    // Optionally, build an error summary as shown in the other fix
  }
});

issues.lineContent:
a:hover, a:focus, input:focus {
  outline: none;
  border-color: transparent;
}

issues.recommendation:
Do not remove the focus outline for inputs. Either remove input:focus from this selector or provide a custom, clearly visible focus style. For example:

/* Keep focus visible for inputs */
input:focus {
  outline: 2px solid #005fcc;
  border-color: #005fcc;
}

/* If you want to suppress focus for mouse users only, use :focus-visible appropriately and avoid removing focus for keyboard navigation. */

Use a button element to trigger actions. Example:
HTML: <button id="openCheatsheet" type="button">Cheat sheet</button>
JS: $('#openCheatsheet').on('click', function () { showModal(); });

Do not remove focus outlines. Either remove this declaration or provide a custom, highly visible focus style. For example:

/* Remove the rule */
/* or */
#modalContent button:focus-visible { outline: 3px solid #1a73e8; outline-offset: 2px; }

Do not remove focus outlines. Provide a strong custom focus style instead. Example:

a:focus-visible, input:focus-visible { outline: 2px solid #005fcc; outline-offset: 2px; border-color: initial; }

If you must override :focus, ensure a visible replacement is provided.

Do not remove the outline, or provide a custom, highly visible focus style. For example:

/* Remove the rule that sets outline: none; */
#modalContent button:focus-visible {
  outline: 2px solid #005fcc;
  outline-offset: 2px;
}

/* If you must reset outline in some cases, ensure an equivalent visible focus style is applied */

Use a button element for actions. Example:
HTML: <button type="button" id="openCheatsheetModal">Cheatsheet</button>
JS: $('#openCheatsheetModal').on('click', function() { showModal(); });

Add a keydown handler on the menu container or items to implement required keyboard navigation and dismissal. Example:

$("#menu").on("keydown", function(e) {
  const $items = $("#menu a");
  const i = $items.index($(document.activeElement));
  switch (e.key) {
    case "ArrowDown": e.preventDefault(); $items.eq(Math.min(i + 1, $items.length - 1)).focus(); break;
    case "ArrowUp": e.preventDefault(); $items.eq(Math.max(i - 1, 0)).focus(); break;
    case "Home": e.preventDefault(); $items.first().focus(); break;
    case "End": e.preventDefault(); $items.last().focus(); break;
    case "ArrowRight": // open submenu if present
      e.preventDefault();
      const $li = $(document.activeElement).closest("li");
      const $sub = $li.children("ul");
      if ($sub.length) { $sub.show(); $sub.find("a").first().focus(); }
      break;
    case "ArrowLeft": // close submenu if open
      e.preventDefault();
      closeSubMenu();
      $li = $(document.activeElement).closest("li");
      $li.children("a").first().focus();
      break;
    case "Escape": e.preventDefault(); closeSubMenu(); $(document.activeElement).closest("li").children("a").first().focus(); break;
  }
});

Bind an Escape key handler to call closeSubMenu and return focus to the triggering element. Example:

$("#menu").on("keydown", function(e) {
  if (e.key === "Escape") {
    e.preventDefault();
    closeSubMenu();
    $(document.activeElement).closest("li").children("a").first().focus();
  }
});

Track the element that opened the submenu and toggle aria-expanded accordingly. For example: 

let currentTrigger = null;

// when opening
currentTrigger = this;
subMenu = $(this).parent('li').children('ul');
subMenu.show();
$(currentTrigger).attr('aria-haspopup','true').attr('aria-expanded','true');

// when closing
function closeSubMenu() {
  if (subMenu) {
    subMenu.hide();
    if (currentTrigger) {
      $(currentTrigger).attr('aria-expanded','false');
    }
    subMenu = null;
    currentTrigger = null;
  }
}

Add keydown handlers to the menu trigger and items to support Arrow keys, Enter/Space, Escape, Home/End, and Tab per ARIA APG. Example:

$('#menu > li > a, #menu > li > button').on('keydown', function(e){
  switch(e.key){
    case 'ArrowDown': /* move to next item */ break;
    case 'ArrowUp':   /* move to previous item */ break;
    case 'ArrowRight':/* open submenu or move to next top-level */ break;
    case 'ArrowLeft': /* close submenu or move to previous top-level */ break;
    case 'Enter':
    case ' ':         /* activate item */ break;
    case 'Escape':    closeSubMenu(); /* return focus to trigger */ this.focus(); break;
    case 'Home':      /* move to first item */ break;
    case 'End':       /* move to last item */ break;
  }
});
// Ensure Tab moves focus out of the menu to the next focusable element.

Update aria-expanded on the trigger when showing/hiding and set aria-controls to the submenu ID. Example:

const trigger = $(this).children('a, button').first();
if (!subMenu.attr('id')) subMenu.attr('id', 'submenu-' + Date.now());
trigger.attr('aria-haspopup', 'true')
       .attr('aria-controls', subMenu.attr('id'))
       .attr('aria-expanded', 'true');
// In closeSubMenu():
function closeSubMenu(){
  if (subMenu){
    subMenu.hide();
    const trigger = subMenu.parent().children('a, button').first();
    trigger.attr('aria-expanded', 'false');
  }
}

Add an Escape key handler to close the menu and return focus to the trigger. Example:

let lastTrigger = null; // set this when opening a submenu
$(document).on('keydown', function(e){
  if (e.key === 'Escape'){
    closeSubMenu();
    if (lastTrigger) $(lastTrigger).focus();
  }
});

Add keydown handlers to support full menu keyboard interaction. Example:
$('#menu').on('keydown', 'a', function(e){
  const items = $(this).closest('ul').find('a:visible');
  const i = items.index(this);
  switch(e.key){
    case 'ArrowDown': e.preventDefault(); items.eq(Math.min(i+1, items.length-1)).focus(); break;
    case 'ArrowUp': e.preventDefault(); items.eq(Math.max(i-1, 0)).focus(); break;
    case 'ArrowRight': e.preventDefault(); const sm=$(this).parent('li').children('ul'); if(sm.length){ $(this).attr('aria-expanded','true'); sm.show().find('a').first().focus(); } break;
    case 'ArrowLeft': e.preventDefault(); const parentTrigger=$(this).closest('ul').closest('li').children('a'); if(parentTrigger.length){ closeSubMenu(); parentTrigger.focus(); } break;
    case 'Home': e.preventDefault(); items.first().focus(); break;
    case 'End': e.preventDefault(); items.last().focus(); break;
    case 'Escape': e.preventDefault(); closeSubMenu(); $(this).closest('li').children('a').focus(); break;
    case 'Enter': case ' ': e.preventDefault(); this.click(); break;
  }
});

When opening a submenu, set aria-expanded="true" on its trigger; when closing, set it to "false". Example:
$(this).attr('aria-expanded','true');
subMenu.show();
// In closeSubMenu():
$('#menu > li > a[aria-expanded="true"]').attr('aria-expanded','false');
$('#menu ul').hide();

Give the submenu a unique id and set aria-controls on the trigger to that id. Example:
var subMenu = $(this).parent('li').children('ul');
var id = subMenu.attr('id');
if(!id){ id = 'submenu-' + Date.now(); subMenu.attr('id', id); }
$(this).attr('aria-controls', id);

issues.lineContent:
$("#menu > li> a")
  .on('focus',function(){
    menuHasFocus = true; 
    // close previously open submenu
    closeSubMenu();
    // get and show new submenu
    subMenu = $(this).parent('li').children('ul');
    subMenu.show();
    clearTimeout(timer);
