Update closeSubMenu to return focus to a stable element (e.g., the parent menu item's trigger) before hiding, and set aria-expanded to false. For example:

function closeSubMenu() {
  if (subMenu && subMenu.is(':visible')) {
    var trigger = subMenu.parent().children('a').first();
    if (subMenu.find(document.activeElement).length) {
      trigger.focus();
    }
    trigger.attr('aria-expanded', 'false');
    subMenu.hide();
  }
}

